const eligibleActions = new Set(["Reactivate", "Get Live", "Relist"]);

return items.filter(i => {
  const action = (i.json["Action to take"] || "").trim();
  const status = (i.json["Contact Status"] || "").trim();
  const kId = (i.json["Kustomer ID"] || "").trim();
  const replied = (i.json["Replied?"] || "").toString().toLowerCase() === "true";
  const hasEmail = !!(i.json["OWNER_EMAIL"] || "").trim();
  const hasPhone = !!(i.json["OWNER_PHONE_NUMBER"] || "").trim();

  if (!kId) return false;

  // NEW readiness condition
  if (status !== "Pending Outreach") return false;

  if (replied) return false;
  if (!eligibleActions.has(action)) return false;
  if (!hasEmail && !hasPhone) return false;

  return true;
});

